    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseB(pNonce * 0xAAEBDC4A7C09332DULL + 0xB685744754212D21ULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseC(pNonce * 0xBA3B764897A0B77FULL + 0x91205DB19A56AFC1ULL);
