    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xB06B658A7F738D23ULL + 0x9C77FF8EB575496AULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xC705F2D36163A97BULL + 0xAAA7B663519BB527ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0xCF02DF16AF9F0703ULL + 0xFF545F0CDE703B00ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0x83B7C31CA3D1D493ULL + 0xF5DD161A27293216ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseA(pNonce * 0xA1CFDD825B5DCF13ULL + 0xB53AEEC05E3BD733ULL);
