    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0x86D9F8DC1888E80FULL + 0xE0CF5F2155FF5F3DULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseC(pNonce * 0xB8B78AA6F9A564D5ULL + 0xE30382FF72162851ULL);
