            //
            aScatter = (RotL64(aCross, 23U) + RotL64(aIngress, 3U)) ^ (RotL64(aPrevious, 52U) + RotL64(aCarry, 39U));
            aScatter = TwistMix64::DiffuseA(((aScatter ^ aDomainWordScatter) ^ aNonceWordJ));
            //
            aOrbiterJ = ((aWandererE + RotL64(aIngress, 6U)) + 3917730204724097072U) + aNonceWordI;
            aOrbiterH = (((aWandererD + RotL64(aPrevious, 43U)) + 1874642340716212824U) + aOrbiterAssignSaltB[((aIndex + 16U)) & S_SALT1]) + aNonceWordK;
            aOrbiterE = (aWandererB + RotL64(aScatter, 51U)) + 6900165757434854160U;
