            aOrbiterJ = RotL64((aOrbiterJ * 3692603590609922031U), 57U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterB) + 6321455513889880590U;
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 1197435601998121700U;
            aOrbiterF = RotL64((aOrbiterF * 17693996266260557625U), 11U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterE) + 12496949381666299968U) + aNonceWordO;
            aOrbiterA = (aOrbiterA ^ aOrbiterD) ^ 6357070235648527030U;
            aOrbiterA = RotL64((aOrbiterA * 2931486644220862433U), 37U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterA) + 8423760160877540210U) + aOrbiterUpdateSaltB[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterB) ^ 8090246492554850768U;
            aOrbiterG = RotL64((aOrbiterG * 2949407491181921633U), 43U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterI) + 11436635942985063755U;
            aOrbiterC = (aOrbiterC ^ aOrbiterH) ^ 17086363141014359856U;
            aOrbiterC = RotL64((aOrbiterC * 10504127577318206801U), 35U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 10734017887545474935U;
