            aOrbiterI = RotL64((aOrbiterI * 9980486695448151709U), 21U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterD) + 5217148491945389821U;
            aOrbiterB = (((aOrbiterB ^ aOrbiterI) ^ 14696058217023530058U) ^ aOrbiterUpdateSaltA[(((31U - aIndex) + 15U)) & S_SALT1]) ^ aNonceWordP;
            aOrbiterB = RotL64((aOrbiterB * 11026674782236654799U), 41U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterC) + 11869055287836412650U;
            aOrbiterK = ((aOrbiterK ^ aOrbiterE) ^ 16951500118659983436U) ^ aOrbiterUpdateSaltF[((aIndex + 11U)) & S_SALT1];
            aOrbiterK = RotL64((aOrbiterK * 4304372681583055077U), 27U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterJ) + 7866300390953569803U;
