            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterJ, 13U));
            aIngress = aIngress + (RotL64(aOrbiterD, 39U) ^ aOrbiterF);
            aIngress = aIngress + RotL64(aOrbiterE, 53U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererC = aWandererC ^ ((RotL64(aCross, 37U) + RotL64(aOrbiterA, 37U)) + aOrbiterG);
            aWandererI = aWandererI + (((RotL64(aIngress, 23U) + RotL64(aOrbiterC, 21U)) + aOrbiterG) + aNonceWordD);
            aWandererD = aWandererD ^ (((RotL64(aPrevious, 28U) + RotL64(aOrbiterH, 39U)) + aOrbiterI) + aNonceWordF);
